self.addEventListener("push",function(i){if(i.data){let t=i.data.json(),n={body:t.body,icon:"/icon.png",badge:"/badge.png",vibrate:[100,50,100],data:{dateOfArrival:Date.now(),primaryKey:"2",url:t.url||"/"}};i.waitUntil(self.registration.showNotification(t.title,n))}}),self.addEventListener("notificationclick",function(i){i.notification.close(),i.waitUntil(self.clients.openWindow(i.notification.data.url))});